const { useState, useEffect } = React;
React.useEffect = useEffect;

const LOGO = "data:image/png;base64,";

const COLORS = {
  navy: "#0F2A4A",
  teal: "#1C7C8C",
  red: "#D9483A",
  green: "#3FA796",
  cream: "#F7FAF9",
};

const NAV = [
  { id: "home", label: "Home" },
  { id: "about", label: "About" },
  { id: "programs", label: "Programs" },
  { id: "volunteer", label: "Volunteer" },
  { id: "events", label: "Events" },
  { id: "resources", label: "Resources" },
  { id: "partners", label: "Partners" },
  { id: "donate", label: "Donate" },
  { id: "contact", label: "Contact" },
];

function Pulse({ flip }) {
  return (
    <svg
      viewBox="0 0 600 60"
      preserveAspectRatio="none"
      style={{ width: "100%", height: 28, display: "block", transform: flip ? "scaleY(-1)" : "none" }}
    >
      <polyline
        points="0,30 130,30 165,8 195,52 225,18 255,30 600,30"
        fill="none"
        stroke={COLORS.red}
        strokeWidth="3"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function Eyebrow({ children }) {
  return (
    <div
      style={{
        fontFamily: "'Space Grotesk', sans-serif",
        fontSize: 12,
        letterSpacing: "0.18em",
        textTransform: "uppercase",
        color: COLORS.teal,
        fontWeight: 700,
        marginBottom: 10,
      }}
    >
      {children}
    </div>
  );
}

function Button({ children, primary, onClick, style }) {
  return (
    <button
      onClick={onClick}
      style={{
        fontFamily: "'Space Grotesk', sans-serif",
        fontWeight: 600,
        fontSize: 15,
        padding: "13px 28px",
        borderRadius: 999,
        border: primary ? "none" : `2px solid ${COLORS.navy}`,
        background: primary ? COLORS.red : "transparent",
        color: primary ? "#fff" : COLORS.navy,
        cursor: "pointer",
        transition: "transform .15s ease, box-shadow .15s ease",
        ...style,
      }}
      onMouseEnter={(e) => (e.currentTarget.style.transform = "translateY(-2px)")}
      onMouseLeave={(e) => (e.currentTarget.style.transform = "translateY(0)")}
    >
      {children}
    </button>
  );
}

function Card({ children, style }) {
  return (
    <div
      style={{
        background: "#fff",
        borderRadius: 16,
        padding: 26,
        boxShadow: "0 8px 28px rgba(15,42,74,0.08)",
        border: "1px solid rgba(15,42,74,0.06)",
        ...style,
      }}
    >
      {children}
    </div>
  );
}

function Section({ children, bg, style }) {
  return (
    <section style={{ background: bg || "transparent", padding: "64px 24px", ...style }}>
      <div style={{ maxWidth: 1080, margin: "0 auto" }}>{children}</div>
    </section>
  );
}

function H2({ children }) {
  return (
    <h2
      style={{
        fontFamily: "'Space Grotesk', sans-serif",
        fontSize: "clamp(26px,4vw,38px)",
        fontWeight: 700,
        color: COLORS.navy,
        margin: "0 0 18px",
        letterSpacing: "-0.01em",
      }}
    >
      {children}
    </h2>
  );
}

function Field({ label, type = "text", textarea, full }) {
  const base = {
    width: "100%",
    padding: "11px 14px",
    borderRadius: 10,
    border: "1.5px solid #D9E2E0",
    fontFamily: "'Inter', sans-serif",
    fontSize: 14,
    color: COLORS.navy,
    outline: "none",
    boxSizing: "border-box",
  };
  return (
    <label style={{ display: "block", gridColumn: full ? "1 / -1" : "auto" }}>
      <span
        style={{
          display: "block",
          fontFamily: "'Space Grotesk', sans-serif",
          fontSize: 12,
          fontWeight: 600,
          color: COLORS.navy,
          marginBottom: 6,
        }}
      >
        {label}
      </span>
      {textarea ? (
        <textarea rows={4} style={{ ...base, resize: "vertical" }} placeholder={`Enter ${label.toLowerCase()}`} />
      ) : (
        <input type={type} style={base} placeholder={`Enter ${label.toLowerCase()}`} />
      )}
    </label>
  );
}

function Stat({ num, label }) {
  return (
    <div>
      <div style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 36, fontWeight: 700, color: COLORS.red }}>
        {num}
      </div>
      <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 13, color: COLORS.navy, opacity: 0.7 }}>{label}</div>
    </div>
  );
}

function Hero({ title, subtitle, eyebrow }) {
  return (
    <div
      style={{
        background: `linear-gradient(160deg, ${COLORS.navy} 0%, #133657 60%, ${COLORS.teal} 130%)`,
        padding: "70px 24px 50px",
        color: "#fff",
      }}
    >
      <div style={{ maxWidth: 1080, margin: "0 auto" }}>
        <Eyebrow>
          <span style={{ color: "#9FD8D2" }}>{eyebrow || "Medical Health Hub Sierra Leone"}</span>
        </Eyebrow>
        <h1
          style={{
            fontFamily: "'Space Grotesk', sans-serif",
            fontSize: "clamp(30px,5vw,48px)",
            fontWeight: 700,
            margin: "0 0 14px",
            maxWidth: 720,
            letterSpacing: "-0.02em",
          }}
        >
          {title}
        </h1>
        <p style={{ fontFamily: "'Inter', sans-serif", fontSize: 17, opacity: 0.85, maxWidth: 560, lineHeight: 1.6 }}>
          {subtitle}
        </p>
      </div>
      <Pulse />
    </div>
  );
}

