// --- Simple organization admin login (no OTP, no Firebase) ---
// Change this password to something private once you're ready to use this for real.
const ORG_ADMIN_EMAIL = "medicalhealthhubsl@gmail.com";
const ORG_ADMIN_PASSWORD = "@Medical232";

// --- EmailJS config for sending real verification codes (no backend needed) ---
// 1. Sign up free at https://www.emailjs.com
// 2. Connect your Gmail (medicalhealthhubsl@gmail.com) as an Email Service
// 3. Create an Email Template with two variables: {{to_email}} and {{code}}
// 4. Paste your Service ID, Template ID, and Public Key below
const EMAILJS_SERVICE_ID = "YOUR_SERVICE_ID";
const EMAILJS_TEMPLATE_ID = "YOUR_TEMPLATE_ID";
const EMAILJS_PUBLIC_KEY = "YOUR_PUBLIC_KEY";

async function sendVerificationEmail(toEmail, code) {
  // If EmailJS isn't configured yet, fail quietly so registration still works
  // in demo mode (code shown on screen instead of emailed).
  if (EMAILJS_SERVICE_ID === "YOUR_SERVICE_ID") return { demo: true };
  const res = await fetch("https://api.emailjs.com/api/v1.0/email/send", {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({
      service_id: EMAILJS_SERVICE_ID,
      template_id: EMAILJS_TEMPLATE_ID,
      user_id: EMAILJS_PUBLIC_KEY,
      template_params: { to_email: toEmail, code },
    }),
  });
  if (!res.ok) throw new Error("Failed to send email");
  return { demo: false };
}

const CONTRIB_YEARS = Array.from({ length: 2035 - 2026 + 1 }, (_, i) => 2026 + i);
const MONTHS = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

function ContributionGrid({ mrc, editable }) {
  const [year, setYear] = useState(2026);
  const [data, setData] = useState(null); // { "2026": [bool x12], ... }
  const [saving, setSaving] = useState(false);

  const load = async () => {
    try {
      const r = await window.storage.get(`contributions:${mrc}`, true);
      setData(JSON.parse(r.value));
    } catch (e) {
      setData({});
    }
  };

  React.useEffect(() => { load(); }, [mrc]);

  const monthsForYear = (data && data[year]) || Array(12).fill(false);

  const toggle = async (i) => {
    if (!editable || saving) return;
    setSaving(true);
    const updated = { ...(data || {}) };
    const arr = [...(updated[year] || Array(12).fill(false))];
    arr[i] = !arr[i];
    updated[year] = arr;
    setData(updated);
    try {
      await window.storage.set(`contributions:${mrc}`, JSON.stringify(updated), true);
    } catch (e) { /* ignore */ }
    setSaving(false);
  };

  if (!data) return <p style={{ fontFamily: "'Inter', sans-serif", fontSize: 13, color: "#8FA0AC" }}>Loading…</p>;

  const paidCount = monthsForYear.filter(Boolean).length;

  return (
    <div>
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 18 }}>
        {CONTRIB_YEARS.map((y) => (
          <span
            key={y}
            onClick={() => setYear(y)}
            style={{
              fontFamily: "'Space Grotesk', sans-serif", fontSize: 12, fontWeight: 700, padding: "6px 12px",
              borderRadius: 999, cursor: "pointer",
              background: year === y ? COLORS.navy : "#fff", color: year === y ? "#fff" : COLORS.navy,
              border: `1.5px solid ${COLORS.navy}`,
            }}
          >
            {y}
          </span>
        ))}
      </div>
      <div style={{ fontFamily: "'Inter', sans-serif", fontSize: 13, color: "#5A6772", marginBottom: 10 }}>
        {paidCount} of 12 months paid in {year}
      </div>
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(70px,1fr))", gap: 8 }}>
        {MONTHS.map((m, i) => {
          const paid = monthsForYear[i];
          return (
            <div
              key={m}
              onClick={() => toggle(i)}
              style={{
                display: "flex", flexDirection: "column", alignItems: "center", gap: 6,
                padding: "10px 6px", borderRadius: 10, cursor: editable ? "pointer" : "default",
                background: paid ? "#E6F4F1" : "#F7FAF9", border: `1.5px solid ${paid ? COLORS.green : "#E3EAE8"}`,
              }}
            >
              <span style={{
                width: 20, height: 20, borderRadius: 5, display: "flex", alignItems: "center", justifyContent: "center",
                background: paid ? COLORS.green : "#fff", border: `1.5px solid ${paid ? COLORS.green : "#C7D4D1"}`,
                color: "#fff", fontSize: 13, fontWeight: 700,
              }}>
                {paid ? "✓" : ""}
              </span>
              <span style={{ fontFamily: "'Space Grotesk', sans-serif", fontSize: 12, fontWeight: 600, color: COLORS.navy }}>{m}</span>
            </div>
          );
        })}
      </div>
    </div>
  );
}


function qrUrl(text) {
  return `https://api.qrserver.com/v1/create-qr-code/?size=160x160&data=${encodeURIComponent(text)}`;
}

